import React from 'react';

const Navbar = () => {
  const links = ["HISTORIA", "PRESENTACIONES", "INICIO", "EMPRESAS", "CONTACTO"];

  const styles = {
    navbar: {
      width: "100%",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      gap: "1.5rem",
      padding: "1rem 0",
      backgroundColor: "white",
      borderBottom: "1px solid #e5e7eb",
    },
  
    link: (isInicio) => ({
      fontSize: "0.875rem",
      letterSpacing: "0.1em",
      fontWeight: isInicio ? "600" : "300",
      color: "#1f2937", // gris oscuro
    }),
  };

  return (
    <nav style={styles.navbar}>
      {links.map((link, index) => (
        <span key={index} style={styles.link(link === "INICIO")}>
          {link}
        </span>
      ))}
    </nav>
  );
};

export default Navbar;
